import { useParams } from "react-router-dom";
import "./styles/Books.css";

const booksData = {
  Literature: ["Pride and Prejudice", "Hamlet", "Macbeth"],
  Fiction: ["The Alchemist", "The Kite Runner"],
  Fantasy: ["Harry Potter", "The Hobbit"],
  "Self Help": ["Atomic Habits", "Deep Work"],
  Biography: ["Wings of Fire", "Steve Jobs"],
  History: ["Sapiens", "Guns Germs Steel"],
  Motivation: ["Think and Grow Rich", "You Can Win"],
  Business: ["Rich Dad Poor Dad", "Zero to One"],
};

function CategoryBooks() {
  const { name } = useParams();
  const books = booksData[name] || [];

  return (
    <div className="books-page">
      <h1 className="books-title">{name}</h1>

      <div className="books-grid">
        {books.map((book, index) => (
          <div key={index} className="book-card">
            <h3>{book}</h3>
          </div>
        ))}
      </div>
    </div>
  );
}

export default CategoryBooks;
